cm=CostModel(64)

def plan(name, pair=True, triple=False):
    reqs=[]
    with open(root/'input_data'/name) as f:
        for line in f: reqs.append(json.loads(line))
    groups={}
    for r in reqs:
        s=align(r['prompt_len'],64)
        groups.setdefault(s,[]).append(r)
    recs=[]; bid=0
    for s,rs in sorted(groups.items()):
        rs=sorted(rs,key=lambda r:(r['gen_len'], r['prompt_len']))
        i=0
        while i<len(rs):
            size=2 if pair and i+1<len(rs) else 1
            if triple and i+2<len(rs):
                # maybe triple tiny gens
                pass
            batch=rs[i:i+size]
            bid+=1
            for r in batch:
                recs.append({'request_id':r['request_id'],'batch_id':f'b-{bid:04d}','shape':{'seq_align':s,'heads_align':32,'hidden_align':4096}})
            i+=size
    reqmap={r['request_id']:r for r in reqs}
    return cm.plan_metrics(reqmap,recs)
for name in ['requests_bucket_1.jsonl','requests_bucket_2.jsonl']:
    m=plan(name)
    print(name,{k:m[k] for k in ['cost','pad_ratio','p95_latency_ms','sequential_timecost']})
