import json, pathlib, sys, collections, heapq
sys.path.append('/app/task_file/scripts')
from cost_model import CostModel, align
root=pathlib.Path('/app/task_file'); cm=CostModel(64)

def prefill_lat(prompt):
    return cm._prefill_lat(prompt)

def dec_cost(S,G):
    return cm._sum_sq_arith(S,G)*cm.c.Kd_attn + (G*S + G*(G-1)/2)*cm.c.Kd_mlp*4096

def dec_lat(S,G):
    return cm._sum_sq_arith(S,G)*cm.c.Td_attn + (G*S + G*(G-1)/2)*cm.c.Td_mlp*4096

def build(name,T):
    reqs=[]
    with open(root/'input_data'/name) as f:
        for line in f: reqs.append(json.loads(line))
    byS=collections.defaultdict(list)
    for r in reqs: byS[align(r['prompt_len'],64)].append(r)
    # exact groups
    groups_by_S=[]
    for S,rs in sorted(byS.items()):
        gmap=collections.defaultdict(list)
        for r in rs: gmap[r['gen_len']].append(r)
        arr=[]
        for G,items in sorted(gmap.items()):
            arr.append({
                'gensum': G*len(items), 'count': len(items), 'gmax': G,
                'reqs': items,
                'max_prefill': max(prefill_lat(r['prompt_len']) for r in items),
                'extra': 0,
            })
        groups_by_S.append((S,arr))
    changed=True
    while changed:
        changed=False
        new_groups_by_S=[]
        for S,arr in groups_by_S:
            out=[]; i=0
            while i<len(arr):
                if i+1<len(arr):
                    a,b=arr[i],arr[i+1]
                    before = a['count']*dec_cost(S,a['gmax']) + b['count']*dec_cost(S,b['gmax']) + 2*cm.c.Kbatch_overhead_cost
                    after = (a['count']+b['count'])*dec_cost(S,b['gmax']) + cm.c.Kbatch_overhead_cost
                    # check extra exceed 0 for all in a under b.gmax
                    decode=dec_lat(S,b['gmax'])+8
                    ok=True
                    for r in a['reqs']+b['reqs']:
                        single_ok = prefill_lat(r['prompt_len']) + dec_lat(S,r['gen_len']) + 8 <= T
                        batch_ok = prefill_lat(r['prompt_len']) + decode <= T
                        if single_ok and not batch_ok:
                            ok=False; break
                    if ok and after <= before:
                        merged={
                            'gensum': a['gensum']+b['gensum'], 'count': a['count']+b['count'], 'gmax': b['gmax'],
                            'reqs': a['reqs']+b['reqs'], 'max_prefill': max(a['max_prefill'],b['max_prefill'])
                        }
                        out.append(merged); i+=2; changed=True; continue
                out.append(arr[i]); i+=1
            new_groups_by_S.append((S,out))
        groups_by_S=new_groups_by_S
    recs=[]; bid=0
    for S,arr in groups_by_S:
        for g in arr:
            bid+=1
            for r in g['reqs']:
                recs.append({'request_id':r['request_id'],'batch_id':f'b-{bid:04d}','shape':{'seq_align':2048,'heads_align':32,'hidden_align':4096}})
    m=cm.plan_metrics({r['request_id']:r for r in reqs},recs)
    print(name,'batches',bid,{k:m[k] for k in ['cost','pad_ratio','p95_latency_ms','sequential_timecost']})

